import * as stylex from "@stylexjs/stylex";
import { VStack } from "../Stack/stack";
import { Text } from "../Text/text";
import { Badge } from "./badge";

const styles = stylex.create({
	grid: {
		display: "flex",
		flexWrap: "wrap",
		gap: "var(--space-2)",
		alignItems: "center",
	},
});

function BadgeDemo() {
	return (
		<VStack gap="medium">
			<Text variant="h6">Variants</Text>
			<div {...stylex.props(styles.grid)}>
				<Badge variant="default">Default</Badge>
				<Badge variant="primary">Primary</Badge>
				<Badge variant="secondary">Secondary</Badge>
			</div>
		</VStack>
	);
}

export { BadgeDemo as Demo };

import { Button } from "../Button/button";
import { Text } from "../Text/text";
import {
	Card,
	CardBody,
	CardDescription,
	CardFooter,
	CardHeader,
	CardTitle,
} from "./card";

function CardDemo() {
	return (
		<Card>
			<CardHeader>
				<CardTitle>Getting Started</CardTitle>
				<CardDescription>
					Learn how to install and use Blenx UI components in your project.
				</CardDescription>
			</CardHeader>
			<CardBody>
				<Text variant="body2">
					Blenx UI provides a set of accessible, styleable React components
					built on Base UI primitives and styled with StyleX.
				</Text>
			</CardBody>
			<CardFooter>
				<Button variant="outline" size="small">
					Read docs
				</Button>
				<Button size="small">Install</Button>
			</CardFooter>
		</Card>
	);
}

export { CardDemo as Demo };

import * as stylex from "@stylexjs/stylex";
import { VStack } from "../Stack/stack";
import { Text } from "../Text/text";
import { Input } from "./input";

const styles = stylex.create({
	grid: {
		display: "flex",
		flexDirection: "column",
		gap: "var(--space-3)",
		maxWidth: 320,
	},
});

function InputDemo() {
	return (
		<VStack gap="medium">
			<div {...stylex.props(styles.grid)}>
				<Text variant="h6">Sizes</Text>
				<Input size="sm" placeholder="Small input" />
				<Input placeholder="Default input" />
				<Input size="lg" placeholder="Large input" />
			</div>

			<div {...stylex.props(styles.grid)}>
				<Text variant="h6">With Error</Text>
				<Input error="This field is required" placeholder="Email address" />
			</div>
		</VStack>
	);
}

export { InputDemo as Demo };

import { HStack, VStack } from "../Stack/stack";
import { Text } from "../Text/text";
import { Switch } from "./switch";

function SwitchDemo() {
	return (
		<VStack gap="medium">
			<HStack gap="medium" align="center">
				<Switch defaultChecked />
				<Text variant="body2">Airplane Mode</Text>
			</HStack>
			<HStack gap="medium" align="center">
				<Switch />
				<Text variant="body2">Wi-Fi</Text>
			</HStack>
			<HStack gap="medium" align="center">
				<Switch disabled />
				<Text variant="body2" color="secondary">
					Bluetooth (disabled)
				</Text>
			</HStack>
		</VStack>
	);
}

export { SwitchDemo as Demo };

import { Badge } from "../Badge/badge";
import { VStack } from "../Stack/stack";
import { Table } from "./table";

interface User {
	id: string;
	name: string;
	email: string;
	role: string;
	status: "active" | "inactive";
}

const users: User[] = [
	{
		id: "1",
		name: "Alice Johnson",
		email: "alice@example.com",
		role: "Admin",
		status: "active",
	},
	{
		id: "2",
		name: "Bob Smith",
		email: "bob@example.com",
		role: "Editor",
		status: "active",
	},
	{
		id: "3",
		name: "Carol Davis",
		email: "carol@example.com",
		role: "Viewer",
		status: "inactive",
	},
];

function TableDemo() {
	const columns = [
		{ key: "name" as keyof User, header: "Name" },
		{ key: "email" as keyof User, header: "Email" },
		{ key: "role" as keyof User, header: "Role" },
		{
			key: "status" as keyof User,
			header: "Status",
			cell: (row: User) => (
				<Badge variant={row.status === "active" ? "primary" : "default"}>
					{row.status}
				</Badge>
			),
		},
	];

	return (
		<VStack gap="medium">
			<Table columnData={columns} rowData={users} rowKey="id" />
		</VStack>
	);
}

export { TableDemo as Demo };
